+    let v: serde_json::Value =
+        serde_json::from_str(&content).map_err(|e| format!("metadata JSON parse failed: {e}"))?;
+
+    let size_bytes = v
+        .get("file_size_bytes")
+        .and_then(serde_json::Value::as_u64)
+        .ok_or_else(|| format!("metadata missing file_size_bytes: {}", meta_path.display()))?;
+    let page_size = v
+        .get("page_size")
+        .and_then(serde_json::Value::as_u64)
+        .and_then(|n| u32::try_from(n).ok())
+        .ok_or_else(|| format!("metadata missing page_size: {}", meta_path.display()))?;
+
+    let journal_mode = v
+        .get("journal_mode")
+        .and_then(serde_json::Value::as_str)
+        .map(str::to_owned);
+    let user_version = v
+        .get("user_version")
+        .and_then(serde_json::Value::as_u64)
+        .and_then(|n| u32::try_from(n).ok());
+    let application_id = v
+        .get("application_id")
+        .and_then(serde_json::Value::as_u64)
+        .and_then(|n| u32::try_from(n).ok());
+
+    Ok((
+        size_bytes,
+        page_size,
+        journal_mode,
+        user_version,
+        application_id,
+    ))
